class SicaklikSensoru:
    def __init__(self, sicaklik=0):
        self._sicaklik = sicaklik

    @property
    def sicaklik(self):
        """Sıcaklık değerini döndürür."""
        return self._sicaklik

    @sicaklik.setter
    def sicaklik(self, yeni_sicaklik):
        """Sıcaklık değerini ayarlar, mutlak sıfır kontrolü yapar."""
        if not isinstance(yeni_sicaklik, (int, float)):
            raise TypeError("Sıcaklık değeri bir sayı olmalıdır.")
        if yeni_sicaklik < -273.15:  # Mutlak sıfır
            raise ValueError("Sıcaklık mutlak sıfırdan ({:.2f} °C) düşük olamaz.".format(-273.15))
        self._sicaklik = yeni_sicaklik

    @sicaklik.deleter
    def sicaklik(self):
        """Sıcaklık değerini siler ve sıfırlar."""
        print("Sıcaklık değeri siliniyor ve varsayılan olarak 0'a ayarlanıyor.")
        del self._sicaklik
        self._sicaklik = 0 # Silindikten sonra varsayılan bir değer atayabiliriz


# Örnek kullanım:
if __name__ == "__main__":
    sensor = SicaklikSensoru(25)

    print(f"Başlangıç sıcaklığı: {sensor.sicaklik}°C")

    sensor.sicaklik = 30
    print(f"Yeni sıcaklık: {sensor.sicaklik}°C")

    # Geçerli olmayan bir değer atamaya çalışalım (tip hatası)
    try:
        sensor.sicaklik = "yirmi"
    except TypeError as e:
        print(f"Hata: {e}")

    # Geçerli olmayan bir değer atamaya çalışalım (değer hatası - mutlak sıfırın altı)
    try:
        sensor.sicaklik = -300
    except ValueError as e:
        print(f"Hata: {e}")

    print(f"Mevcut sıcaklık: {sensor.sicaklik}°C")

    # Sıcaklık değerini silme
    del sensor.sicaklik
    print(f"Sıcaklık silindikten sonra: {sensor.sicaklik}°C")

    sensor.sicaklik = 15.5
    print(f"Tekrar ayarlanan sıcaklık: {sensor.sicaklik}°C")
